INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 102711, 10, 1, 16614068, 0, 11, 16614, "誕生、日……？\n私のですか？\nなぜそんなことを\n覚えているのですか？");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 16614069, "", 91, 16614, "");
