INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, "", "vo_wac_18814", 0, "", 18814090, "", 21, 18814, "vo_wac_18814_004");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 101311, 10, 1, 18814091, 0, 11, 18814, "なんという僥倖ッ！\nみなさま、感謝いたしますぞ～！！\n期待に応えてこれからも、ぐうかわ\n魔法少女として邁進していくことを……");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 18814092, "", 91, 18814, "");
