INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", "", 105311, 1, "", 19814074, "", 3, 19814, "wac_birthday_talk_anger");
