INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 110911, 10, 1, 21314055, 0, 11, 21314, "きゃん！？　何かしらこのケーキ！\nえっ、えっ、もしかして今日って、\n誰かの誕生日だったりしました？");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 21314056, "", 91, 21314, "");
