INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0.2, "", "", 105311, 1, "", 23814077, "", 3, 23814, "wac_birthday_talk_doya");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, "", "vo_wac_23814", 0, "", 23814078, "", 21, 23814, "vo_wac_23814_002");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 105311, 10, 1, 23814079, 0, 11, 23814, "うむ、ツッコむのもめんどくさい。\nともあれ、健康に誕生日を\n迎えたことはめでたいことだ！\nおめでとう、ユキ！");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 23814080, "", 91, 23814, "");
