INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 104911, 10, 1, 25214056, 0, 11, 25214, "わあ、素敵なケーキだね。\nお姉ちゃんのために\n弟くんが用意してくれたの？\n愛を感じちゃうなあ。");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 25214057, "", 91, 25214, "");
