INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 104911, 10, 1, 25214071, 0, 11, 25214, "そんなことないよ～。\nありがとうね、マスター、リノちゃん。\n弟くんにはこのあとたっぷりと\n付き合ってもらうから大丈夫だよ。ね？");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 25214072, "", 91, 25214, "");
