INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 100711, 10, 1, 31114076, 0, 11, 31114, "それならプリンがいいの～！\nこのケーキと同じくらい、でっかい\nプリンが食べたいの～！");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 31114077, "", 91, 31114, "");
