INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 105211, 10, 1, 32114070, 0, 11, 32114, "今さら気にするくらいなら、\n普段からしっかりやればいいのに。\n……なんてお小言はさておき、\nお誕生日おめでとう、リンちゃん♪");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 32114071, "", 91, 32114, "");
