INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", 0, "", "vo_wac_32314", 0, "", 32314062, "", 21, 32314, "vo_wac_32314_001");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 101611, 10, 1, 32314063, 0, 11, 32314, "ミサキっち、ホントおめでと～！\nとりま、飲み物はコーヒーでよさげ？\nお店で大人っぽい味でよろ～って\n頼んだら、おに苦くされたけど！");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 32314064, "", 91, 32314, "");
