INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 105011, 10, 1, 32314068, 0, 11, 32314, "えっ！？\nそ、それは、その～……\n大人のレディ向けジュースとかないの？\n苦いのも、別にダメじゃないけど！");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 32314069, "", 91, 32314, "");
