INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 101811, 10, 1, 32314073, 0, 11, 32314, "ふふっ、ちゃんとあるわよ♪\nこうやってオシャレなグラスに\nぶどうジュースを注げば……\nほら、大人っぽいでしょう？");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 32314074, "", 91, 32314, "");
