INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES (0, 1, 0.5, 103211, 10, 1, 39114063, 0, 11, 39114, "本当に、ありがとうございます……！\n私、このように誕生日を祝ってくれる\n友人に恵まれて、幸せ者です！");
INSERT INTO `v1_132b70b8a6f7f6d98e17a2faf41907feab7862676fc51b4d13e8661eab4d0b76` VALUES ("", "", "", 0, "", "", 39114064, "", 91, 39114, "");
